example.code:
// package.json
{
  "name": "acme",
  "packageManager": "pnpm@9.6.0",
  "engines": { "node": ">=20" },
  "scripts": { "test": "vitest" }
}

// .npmrc
shamefully-hoist=false
engine-strict=true

// .github/workflows/ci.yml
- run: corepack enable
- run: pnpm install --frozen-lockfile
- run: pnpm test

// package.json — REJECTED
{"name": "acme", "scripts": {"start": "node index.js"}}
// .npmrc
shamefully-hoist=true
// CI: `pnpm install` (no --frozen-lockfile)
